import React, { useState, useMemo } from 'react';
import { CalendarDays, Plus, Trash2, Wand2, Key, Users, X, Wine, RefreshCw, Search, Link as LinkIcon, AlertCircle } from 'lucide-react';
import { AppDataV1, Culto, Obreiro } from '../types';
import { MONTHS, DEFAULT_CULTOS, DAYS_FULL } from '../constants';

interface Props {
  data: AppDataV1;
  setData: React.Dispatch<React.SetStateAction<AppDataV1>>;
}

const GerenciarMesTab: React.FC<Props> = ({ data, setData }) => {
  const [showAddManual, setShowAddManual] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showPicker, setShowPicker] = useState<{ cultoId: string, role: string } | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [newCulto, setNewCulto] = useState({
    date: '',
    time: '19:30',
    name: '',
    isSantaCeia: false
  });

  const currentYear = new Date().getFullYear();
  const years = Array.from({ length: 7 }, (_, i) => currentYear - 1 + i);

  // Calcula os cultos do mês selecionado a partir da lista global
  const cultosDoMes = useMemo(() => {
    return data.cultos.filter(c => {
      const d = new Date(c.date + "T12:00:00");
      return d.getMonth() === data.currentMonth && d.getFullYear() === data.currentYear;
    }).sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time));
  }, [data.cultos, data.currentMonth, data.currentYear]);

  // Função para recalcular saldo considerando TODA a história (todos os cultos em data.cultos)
  const recalculateGlobalBalances = (obreiros: Obreiro[], allCultos: Culto[]): Obreiro[] => {
    return obreiros.map(obreiro => {
      const count = allCultos.reduce((acc, culto) => {
        const isAbertura = culto.workersAbertura.includes(obreiro.id);
        const isApoio = culto.workersApoio.includes(obreiro.id);
        return acc + (isAbertura ? 1 : 0) + (isApoio ? 1 : 0);
      }, 0);
      return { ...obreiro, balance: count };
    });
  };

  const handleMonthChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setData(prev => ({ ...prev, currentMonth: parseInt(e.target.value) }));
  };

  const handleYearChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setData(prev => ({ ...prev, currentYear: parseInt(e.target.value) }));
  };

  const handleGenerateBase = () => {
    if (cultosDoMes.length > 0 && !confirm(`Já existem ${cultosDoMes.length} cultos em ${MONTHS[data.currentMonth]}. Deseja adicionar os cultos padrão do sistema a este mês?`)) return;

    const daysInMonth = new Date(data.currentYear, data.currentMonth + 1, 0).getDate();
    const generated: Culto[] = [];

    for (let day = 1; day <= daysInMonth; day++) {
      const date = new Date(data.currentYear, data.currentMonth, day);
      const dayOfWeek = date.getDay();
      const dayCultos = DEFAULT_CULTOS.filter(c => c.day === dayOfWeek);

      dayCultos.forEach(c => {
        const dateStr = date.toISOString().split('T')[0];
        // Evita duplicados exatos (mesma data, mesmo nome, mesmo horário)
        const exists = data.cultos.some(old => old.date === dateStr && old.time === c.time && old.name === c.name);

        if (!exists) {
          generated.push({
            id: crypto.randomUUID(),
            date: dateStr,
            dayOfWeek,
            time: c.time,
            name: c.name,
            isSantaCeia: false,
            workersAbertura: [],
            workersApoio: [],
            santaCeiaWorkers: { arrumarMesa: '', desarrumarMesa: '', servirPao: '', servirVinho: '' }
          });
        }
      });
    }

    if (generated.length === 0) {
      alert("Nenhum novo culto padrão foi adicionado (eles já existem para este mês).");
      return;
    }

    setData(prev => ({
      ...prev,
      cultos: [...prev.cultos, ...generated].sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time))
    }));
  };

  const handleClearMonthSchedule = () => {
    if (cultosDoMes.length === 0) return;
    if (!confirm(`Deseja remover todos os obreiros escalados APENAS no mês de ${MONTHS[data.currentMonth]}?`)) return;

    setData(prev => {
      const updatedCultos = prev.cultos.map(c => {
        const d = new Date(c.date + "T12:00:00");
        if (d.getMonth() === data.currentMonth && d.getFullYear() === data.currentYear) {
          return {
            ...c,
            workersAbertura: [],
            workersApoio: [],
            santaCeiaWorkers: { arrumarMesa: '', desarrumarMesa: '', servirPao: '', servirVinho: '' }
          };
        }
        return c;
      });
      return { ...prev, cultos: updatedCultos, obreiros: recalculateGlobalBalances(prev.obreiros, updatedCultos) };
    });
  };

  const handleAddManual = () => {
    if (!newCulto.date || !newCulto.name) return alert("Preencha a data e o nome.");
    const dateObj = new Date(newCulto.date + "T12:00:00");
    const culto: Culto = {
      id: crypto.randomUUID(),
      date: newCulto.date,
      dayOfWeek: dateObj.getDay(),
      time: newCulto.time,
      name: newCulto.name,
      isSantaCeia: newCulto.isSantaCeia,
      workersAbertura: [],
      workersApoio: [],
      santaCeiaWorkers: { arrumarMesa: '', desarrumarMesa: '', servirPao: '', servirVinho: '' }
    };

    setData(prev => ({ 
      ...prev, 
      cultos: [...prev.cultos, culto].sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time)) 
    }));

    setNewCulto({ date: '', time: '19:30', name: '', isSantaCeia: false });
    setShowAddManual(false);
  };

  const assignWorker = (cultoId: string, obreiroId: string, role: string) => {
    setData(prev => {
      const obreiro = prev.obreiros.find(o => o.id === obreiroId);
      const updatedCultos = prev.cultos.map(c => {
        if (c.id !== cultoId) return c;

        if (role === 'abertura' || role === 'apoio') {
          let workersAbertura = c.workersAbertura.filter(id => id !== obreiroId);
          let workersApoio = c.workersApoio.filter(id => id !== obreiroId);

          if (role === 'abertura') {
            workersAbertura = [obreiroId];
            if (obreiro?.linkedWorkerId && workersApoio.length === 0) {
              workersApoio = [obreiro.linkedWorkerId];
            }
          } else {
            workersApoio = [obreiroId];
            if (obreiro?.linkedWorkerId && workersAbertura.length === 0) {
              workersAbertura = [obreiro.linkedWorkerId];
            }
          }

          return { ...c, workersAbertura, workersApoio };
        }

        return { ...c, santaCeiaWorkers: { ...(c.santaCeiaWorkers || { arrumarMesa: '', desarrumarMesa: '', servirPao: '', servirVinho: '' }), [role]: obreiroId } };
      });
      return { ...prev, cultos: updatedCultos, obreiros: recalculateGlobalBalances(prev.obreiros, updatedCultos) };
    });
    setShowPicker(null);
  };

  const removeWorker = (cultoId: string, obreiroId: string, role: string) => {
    setData(prev => {
      const updatedCultos = prev.cultos.map(c => {
        if (c.id !== cultoId) return c;
        if (role === 'abertura') return { ...c, workersAbertura: c.workersAbertura.filter(id => id !== obreiroId) };
        if (role === 'apoio') return { ...c, workersApoio: c.workersApoio.filter(id => id !== obreiroId) };
        return { ...c, santaCeiaWorkers: { ...(c.santaCeiaWorkers || { arrumarMesa: '', desarrumarMesa: '', servirPao: '', servirVinho: '' }), [role]: '' } };
      });
      return { ...prev, cultos: updatedCultos, obreiros: recalculateGlobalBalances(prev.obreiros, updatedCultos) };
    });
  };

  const handleGenerateScale = () => {
    if (data.obreiros.length < 2) return alert("Mínimo 2 obreiros.");
    if (cultosDoMes.length === 0) return alert("Não há cultos criados para este mês.");

    setIsGenerating(true);

    setData(prev => {
      let tempObreiros = JSON.parse(JSON.stringify(prev.obreiros)) as Obreiro[];
      const globalCultos = JSON.parse(JSON.stringify(prev.cultos)) as Culto[];

      // Identifica quais cultos pertencem ao mês ativo para processar apenas estes
      const cultosToProcess = globalCultos.filter(c => {
        const d = new Date(c.date + "T12:00:00");
        return d.getMonth() === data.currentMonth && d.getFullYear() === data.currentYear;
      }).sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time));

      cultosToProcess.forEach((culto) => {
        const d = new Date(culto.date + "T12:00:00");
        const slotId = (d.getDay() === 0) ? (parseInt(culto.time.split(':')[0]) < 14 ? 0 : 7) : d.getDay();

        const selectForRole = (target: 'abertura' | 'apoio') => {
          const otherRole = target === 'abertura' ? 'apoio' : 'abertura';
          const currentList = target === 'abertura' ? culto.workersAbertura : culto.workersApoio;
          const otherList = target === 'abertura' ? culto.workersApoio : culto.workersAbertura;

          if (currentList.length >= 1) return;

          // Regra de vínculo (parceiro)
          if (otherList.length > 0) {
            const personAlreadyIn = tempObreiros.find(o => o.id === otherList[0]);
            if (personAlreadyIn?.linkedWorkerId) {
              const partner = tempObreiros.find(o => o.id === personAlreadyIn.linkedWorkerId);
              if (partner && !partner.restrictions.includes(slotId) && !culto.workersAbertura.includes(partner.id) && !culto.workersApoio.includes(partner.id)) {
                 if (target === 'abertura') culto.workersAbertura.push(partner.id);
                 else culto.workersApoio.push(partner.id);
                 partner.balance += 1;
                 return;
              }
            }
          }

          // Busca candidatos respeitando restrições e especialidades
          let candidates = tempObreiros.filter(o => 
            !o.restrictions.includes(slotId) && 
            !culto.workersAbertura.includes(o.id) && 
            !culto.workersApoio.includes(o.id) && 
            (o.preferredRole === target || o.preferredRole === 'ambos')
          );

          if (candidates.length === 0) {
            candidates = tempObreiros.filter(o => 
              !o.restrictions.includes(slotId) && 
              !culto.workersAbertura.includes(o.id) && 
              !culto.workersApoio.includes(o.id)
            );
          }

          if (candidates.length === 0) return;

          // Nivelamento pelo saldo GLOBAL (quem trabalhou menos na história ganha prioridade)
          const minBal = Math.min(...candidates.map(o => o.balance));
          const eligible = candidates.filter(o => o.balance === minBal);
          const winner = eligible[Math.floor(Math.random() * eligible.length)];

          const targetWorker = tempObreiros.find(o => o.id === winner.id);
          if (targetWorker) {
            if (target === 'abertura') culto.workersAbertura.push(targetWorker.id); 
            else culto.workersApoio.push(targetWorker.id);
            targetWorker.balance += 1;

            // Se o escolhido tem parceiro, tenta encaixar o parceiro no outro slot
            if (targetWorker.linkedWorkerId && otherList.length === 0) {
               const partner = tempObreiros.find(o => o.id === targetWorker.linkedWorkerId);
               if (partner && !partner.restrictions.includes(slotId)) {
                 if (otherRole === 'abertura') culto.workersAbertura.push(partner.id);
                 else culto.workersApoio.push(partner.id);
                 partner.balance += 1;
               }
            }
          }
        };

        selectForRole('abertura');
        selectForRole('apoio');
      });

      return { 
        ...prev, 
        cultos: globalCultos, 
        obreiros: recalculateGlobalBalances(tempObreiros, globalCultos) 
      };
    });

    setTimeout(() => { 
      setIsGenerating(false); 
      alert(`Escala de ${MONTHS[data.currentMonth]} distribuída com sucesso mantendo o histórico de saldos.`); 
    }, 800);
  };

  const filteredCultos = cultosDoMes.filter(culto => {
    if (!searchTerm) return true;
    const s = searchTerm.toLowerCase();
    const getObreiroName = (id: string) => data.obreiros.find(o => o.id === id)?.name.toLowerCase() || '';
    const namesInCulto = [
      ...culto.workersAbertura.map(getObreiroName), 
      ...culto.workersApoio.map(getObreiroName), 
      getObreiroName(culto.santaCeiaWorkers?.arrumarMesa || ''), 
      getObreiroName(culto.santaCeiaWorkers?.desarrumarMesa || ''), 
      getObreiroName(culto.santaCeiaWorkers?.servirPao || ''), 
      getObreiroName(culto.santaCeiaWorkers?.servirVinho || '')
    ];
    return namesInCulto.some(name => name.includes(s));
  });

  return (
    <div className="space-y-6 pb-20">
      <div className="bg-white p-6 rounded-[40px] shadow-sm border border-slate-100">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-black flex items-center gap-2 text-blue-900 uppercase tracking-tighter"><CalendarDays size={24} /> Gerenciar Mês</h2>
          <div className="bg-emerald-50 px-3 py-1 rounded-full flex items-center gap-2 border border-emerald-100">
            <RefreshCw size={12} className="text-emerald-600 animate-spin-slow" />
            <span className="text-[10px] font-black text-emerald-700 uppercase">Modo Multi-Escalas</span>
          </div>
        </div>

        <div className="flex flex-col sm:flex-row gap-4 mb-4">
          <div className="flex gap-3 flex-grow">
            <select 
              value={data.currentMonth} 
              onChange={handleMonthChange} 
              className="flex-grow p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-blue-900 uppercase outline-none focus:ring-2 focus:ring-blue-100"
            >
              {MONTHS.map((m, idx) => <option key={m} value={idx}>{m}</option>)}
            </select>
            <select 
              value={data.currentYear} 
              onChange={handleYearChange} 
              className="min-w-[110px] p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-blue-900 outline-none focus:ring-2 focus:ring-blue-100"
            >
              {years.map(y => <option key={y} value={y}>{y}</option>)}
            </select>
          </div>
          <div className="flex items-stretch gap-2">
            <button onClick={handleGenerateBase} className="flex-grow sm:flex-none px-6 bg-blue-50 text-blue-700 border border-blue-100 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Criar Cultos Base</button>
            <button onClick={() => setShowAddManual(true)} className="bg-slate-900 text-white p-4 rounded-2xl active:scale-95 transition-transform shadow-lg flex items-center justify-center min-w-[56px]"><Plus size={24} /></button>
          </div>
        </div>

        {cultosDoMes.length === 0 ? (
          <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-[32px] p-10 text-center flex flex-col items-center gap-4">
            <AlertCircle size={40} className="text-slate-300" />
            <div className="space-y-1">
              <p className="font-black text-slate-400 uppercase tracking-widest text-sm italic">Nenhum culto para {MONTHS[data.currentMonth].toUpperCase()}</p>
              <p className="text-[10px] font-bold text-slate-300 uppercase">Clique em "Criar Cultos Base" para começar este mês.</p>
            </div>
          </div>
        ) : (
          <>
            <div className="relative mb-6">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
              <input type="text" placeholder="Filtrar por nome do obreiro..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-900 placeholder:text-slate-300 focus:ring-2 focus:ring-blue-100 outline-none transition-all" />
              {searchTerm && <button onClick={() => setSearchTerm('')} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-rose-500"><X size={18} /></button>}
            </div>

            {!searchTerm && (
              <div className="flex flex-col gap-3">
                <button onClick={handleGenerateScale} disabled={isGenerating} className={`w-full py-6 rounded-[24px] text-white font-black flex items-center justify-center gap-4 shadow-2xl transition-all ${isGenerating ? 'bg-slate-400' : 'bg-blue-900 active:scale-95'}`}><Wand2 size={24} /> {isGenerating ? 'DISTRIBUINDO...' : 'DISTRIBUIR NO MÊS (GLOBAL)'}</button>
                <button onClick={handleClearMonthSchedule} className="w-full py-4 border-2 border-slate-100 rounded-[20px] text-slate-400 font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-slate-50 transition-colors active:scale-95"><RefreshCw size={16} /> Limpar Escala deste Mês</button>
              </div>
            )}
          </>
        )}
      </div>

      <div className="space-y-4">
        {filteredCultos.map((culto) => (
          <div key={culto.id} className="bg-white p-6 rounded-[48px] border border-slate-100 shadow-sm animate-in fade-in zoom-in-95">
            <div className="flex justify-between items-start mb-6">
              <div>
                <div className="flex items-center gap-2 mb-2">
                  <span className="text-[10px] font-black bg-blue-900 text-white px-3 py-1 rounded-full">{culto.date.split('-').reverse().join('/')}</span>
                  <span className={`text-[10px] font-black px-3 py-1 rounded-full ${culto.isSantaCeia ? 'bg-purple-100 text-purple-700' : 'bg-slate-100 text-slate-500'}`}>{culto.isSantaCeia ? 'SANTA CEIA' : culto.name.toUpperCase()}</span>
                </div>
                <h4 className="font-black text-slate-900 text-xl uppercase tracking-tighter">{DAYS_FULL[culto.dayOfWeek]} • {culto.time}H</h4>
              </div>
              <div className="flex gap-2">
                <button 
                  onClick={() => {
                    setData(prev => ({
                      ...prev,
                      cultos: prev.cultos.map(c => c.id === culto.id ? { ...c, isSantaCeia: !c.isSantaCeia } : c)
                    }));
                  }} 
                  className={`p-4 rounded-2xl border shadow-sm transition-all ${culto.isSantaCeia ? 'bg-purple-600 border-purple-600 text-white shadow-purple-200' : 'bg-slate-50 border-slate-100 text-slate-300 hover:text-purple-400'}`}
                >
                  <Wine size={20} />
                </button>
                <button 
                  onClick={() => {
                    if (confirm("Remover este culto permanentemente?")) {
                      setData(prev => {
                        const updatedCultos = prev.cultos.filter(c => c.id !== culto.id);
                        return { ...prev, cultos: updatedCultos, obreiros: recalculateGlobalBalances(prev.obreiros, updatedCultos) };
                      });
                    }
                  }} 
                  className="p-4 bg-slate-50 text-slate-300 rounded-2xl border border-slate-100 shadow-sm hover:text-rose-500 hover:bg-rose-50 transition-colors"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-4">
                <div className="bg-blue-50/40 p-4 rounded-[32px] border border-blue-50/50">
                  <span className="text-[9px] font-black text-blue-900 uppercase block mb-3">Abertura</span>
                  {culto.workersAbertura.map(wid => {
                    const obreiro = data.obreiros.find(x => x.id === wid);
                    return (
                      <div key={wid} className="bg-white p-3 rounded-xl border border-blue-100 flex justify-between items-center mb-2 shadow-sm">
                        <div className="flex items-center gap-2">
                          <span className="text-xs font-black text-slate-900 uppercase">{obreiro?.name}</span>
                          <span className="text-[9px] font-black bg-blue-100 text-blue-600 px-1.5 py-0.5 rounded-full" title="Saldo Global">
                            {obreiro?.balance || 0}
                          </span>
                          {obreiro?.linkedWorkerId && <LinkIcon size={10} className="text-blue-400" />}
                        </div>
                        <button onClick={() => removeWorker(culto.id, wid, 'abertura')} className="text-rose-400 hover:text-rose-600 transition-colors"><X size={16} /></button>
                      </div>
                    );
                  })}
                  {culto.workersAbertura.length === 0 && <button onClick={() => setShowPicker({ cultoId: culto.id, role: 'abertura' })} className="w-full py-3 border-2 border-dashed border-blue-200 rounded-xl text-[10px] font-black text-blue-300 uppercase hover:bg-blue-50/50 transition-colors">+ Abertura</button>}
                </div>
                <div className="bg-emerald-50/40 p-4 rounded-[32px] border border-emerald-50/50">
                  <span className="text-[9px] font-black text-emerald-900 uppercase block mb-3">Apoio</span>
                  {culto.workersApoio.map(wid => {
                    const obreiro = data.obreiros.find(x => x.id === wid);
                    return (
                      <div key={wid} className="bg-white p-3 rounded-xl border border-emerald-100 flex justify-between items-center mb-2 shadow-sm">
                        <div className="flex items-center gap-2">
                          <span className="text-xs font-black text-slate-900 uppercase">{obreiro?.name}</span>
                          <span className="text-[9px] font-black bg-emerald-100 text-emerald-600 px-1.5 py-0.5 rounded-full" title="Saldo Global">
                            {obreiro?.balance || 0}
                          </span>
                          {obreiro?.linkedWorkerId && <LinkIcon size={10} className="text-emerald-400" />}
                        </div>
                        <button onClick={() => removeWorker(culto.id, wid, 'apoio')} className="text-rose-400 hover:text-rose-600 transition-colors"><X size={16} /></button>
                      </div>
                    );
                  })}
                  {culto.workersApoio.length === 0 && <button onClick={() => setShowPicker({ cultoId: culto.id, role: 'apoio' })} className="w-full py-3 border-2 border-dashed border-emerald-200 rounded-xl text-[10px] font-black text-emerald-300 uppercase hover:bg-emerald-50/50 transition-colors">+ Apoio</button>}
                </div>
              </div>

              {culto.isSantaCeia && (
                <div className="bg-purple-50/40 p-4 rounded-[32px] border border-purple-100 space-y-2">
                  <span className="text-[9px] font-black text-purple-900 uppercase block mb-2">Equipe Santa Ceia</span>
                  {[{ key: 'arrumarMesa', label: 'Arrumação' }, { key: 'desarrumarMesa', label: 'Desarrumação' }, { key: 'servirPao', label: 'Pão' }, { key: 'servirVinho', label: 'Vinho' }].map(role => {
                    const wid = culto.santaCeiaWorkers?.[role.key as keyof typeof culto.santaCeiaWorkers];
                    const obreiro = data.obreiros.find(o => o.id === wid);
                    return (
                      <div key={role.key} className="bg-white/80 p-2 rounded-xl border border-purple-100 flex flex-col">
                        <span className="text-[8px] font-black text-purple-400 uppercase leading-none mb-1">{role.label}</span>
                        {wid ? (
                          <div className="flex justify-between items-center">
                            <div className="flex items-center gap-1.5">
                              <span className="text-[10px] font-black text-slate-900 truncate uppercase">{obreiro?.name}</span>
                              <span className="text-[8px] font-black bg-slate-100 text-slate-400 px-1 rounded-full">S: {obreiro?.balance || 0}</span>
                            </div>
                            <button onClick={() => removeWorker(culto.id, '', role.key)} className="text-rose-400 p-1 hover:text-rose-600"><X size={12} /></button>
                          </div>
                        ) : (
                          <button onClick={() => setShowPicker({ cultoId: culto.id, role: role.key })} className="text-[9px] font-black text-purple-600 uppercase text-left hover:underline">+ Selecionar</button>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {showPicker && (
        <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center"><h3 className="font-black uppercase tracking-tighter">Selecionar Obreiro</h3><button onClick={() => setShowPicker(null)} className="p-2 hover:bg-white/10 rounded-full"><X size={24} /></button></div>
            <div className="p-4 max-h-[60vh] overflow-y-auto space-y-2">
              {data.obreiros.sort((a,b) => a.name.localeCompare(b.name)).map(o => (
                <button key={o.id} onClick={() => assignWorker(showPicker.cultoId, o.id, showPicker.role)} className="w-full p-4 flex justify-between items-center rounded-2xl border border-slate-100 hover:bg-slate-50 transition-colors group">
                  <div className="text-left">
                    <div className="flex items-center gap-1">
                      <span className="text-[9px] font-black text-slate-400 uppercase block leading-none">{o.role}</span>
                      {o.linkedWorkerId && <LinkIcon size={10} className="text-blue-400" />}
                    </div>
                    <span className="font-black text-slate-900 uppercase text-sm group-hover:text-blue-600">{o.name}</span>
                  </div>
                  <div className="text-right">
                    <span className="text-[8px] font-black text-slate-300 uppercase block leading-none mb-1">Saldo Global</span>
                    <span className="text-xs font-black text-blue-600">{o.balance}</span>
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {showAddManual && (
        <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center"><h3 className="font-black uppercase tracking-tighter">Novo Culto Manual</h3><button onClick={() => setShowAddManual(false)} className="p-2 hover:bg-white/10 rounded-full"><X size={24} /></button></div>
            <div className="p-6 space-y-4">
              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Data</label>
                <input type="date" value={newCulto.date} onChange={e => setNewCulto({...newCulto, date: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none" />
              </div>
              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Horário</label>
                <input type="time" value={newCulto.time} onChange={e => setNewCulto({...newCulto, time: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none" />
              </div>
              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Nome do Evento</label>
                <input type="text" value={newCulto.name} onChange={e => setNewCulto({...newCulto, name: e.target.value})} placeholder="EX: CULTO DE DOUTRINA" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none uppercase" />
              </div>
              <button onClick={() => setNewCulto({...newCulto, isSantaCeia: !newCulto.isSantaCeia})} className={`w-full p-4 rounded-2xl border-2 flex items-center justify-between transition-all ${newCulto.isSantaCeia ? 'bg-purple-50 border-purple-200 text-purple-700' : 'bg-white border-slate-100 text-slate-400'}`}>
                <span className="font-black uppercase tracking-tighter">É Santa Ceia?</span>
                <Wine size={20} className={newCulto.isSantaCeia ? 'text-purple-600' : 'text-slate-200'} />
              </button>
              <button onClick={handleAddManual} className="w-full py-5 bg-blue-900 text-white rounded-[24px] font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all mt-4">Adicionar Culto</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default GerenciarMesTab;

import React, { useRef, useState, useMemo } from 'react';
import { Key, Users, Search, X, Smartphone, Printer, Share2, CalendarDays, FileDown, ChevronLeft, ChevronRight, Zap, ShieldCheck, Quote, Calendar } from 'lucide-react';
import { AppDataV1, Culto } from '../types';
import { MONTHS, DAYS_SHORT } from '../constants';

interface Props {
  data: AppDataV1;
  setData?: React.Dispatch<React.SetStateAction<AppDataV1>>;
}

const RelatorioTab: React.FC<Props> = ({ data, setData }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [filterName, setFilterName] = useState('');
  const [viewMode, setViewMode] = useState<'print' | 'mobile' | 'weekly'>('weekly');
  const [selectedWeek, setSelectedWeek] = useState(0);

  const reportRef = useRef<HTMLDivElement>(null);

  // Refs para visualização (com escala)
  const weeklyPreviewRef = useRef<HTMLDivElement>(null);
  const mobilePreviewRef = useRef<HTMLDivElement>(null);

  // Refs para exportação (ocultos, sem escala, largura fixa)
  const weeklyExportRef = useRef<HTMLDivElement>(null);
  const mobileExportRef = useRef<HTMLDivElement>(null);

  const WHATSAPP_MESSAGE = "Paz, obreiros. Atenção à escala. Deus se agrade do trabalho de nossas mãos. Qualquer dificuldade me avisem.";

  const currentYear = new Date().getFullYear();
  const years = Array.from({ length: 7 }, (_, i) => currentYear - 1 + i);

  const handleMonthChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setData?.(prev => ({ ...prev, currentMonth: parseInt(e.target.value) }));
    setSelectedWeek(0);
  };

  const handleYearChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setData?.(prev => ({ ...prev, currentYear: parseInt(e.target.value) }));
    setSelectedWeek(0);
  };

  const getWorkerDisplayName = (id: string | undefined) => {
    if (!id) return '---';
    const obreiro = data.obreiros.find(o => o.id === id);
    if (!obreiro) return '---';
    const name = obreiro.name.length > 40 ? obreiro.name.substring(0, 37) + '...' : obreiro.name;
    return `${obreiro.role} ${name}`.toUpperCase();
  };

  // Filtra cultos pelo mês e ano selecionados, além do filtro de nome
  const sortedCultos = useMemo(() => {
    return [...data.cultos]
      .filter(culto => {
        const d = new Date(culto.date + "T12:00:00");
        return d.getMonth() === data.currentMonth && d.getFullYear() === data.currentYear;
      })
      .sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time))
      .filter(culto => {
        if (!filterName) return true;
        const f = filterName.toLowerCase();
        const getObreiroName = (id: string) => data.obreiros.find(o => o.id === id)?.name.toLowerCase() || '';
        const namesInCulto = [
          ...culto.workersAbertura.map(getObreiroName), 
          ...culto.workersApoio.map(getObreiroName), 
          getObreiroName(culto.santaCeiaWorkers?.arrumarMesa || ''), 
          getObreiroName(culto.santaCeiaWorkers?.desarrumarMesa || ''), 
          getObreiroName(culto.santaCeiaWorkers?.servirPao || ''), 
          getObreiroName(culto.santaCeiaWorkers?.servirVinho || '')
        ];
        return namesInCulto.some(name => name.includes(f));
      });
  }, [data.cultos, data.obreiros, filterName, data.currentMonth, data.currentYear]);

  const weeks = useMemo(() => {
    if (sortedCultos.length === 0) return [];
    const weeksMap = new Map<string, Culto[]>();
    sortedCultos.forEach(culto => {
      const d = new Date(culto.date + "T12:00:00");
      const day = d.getDay(); 
      const diffToMonday = day === 0 ? 6 : day - 1;
      const monday = new Date(d);
      monday.setDate(d.getDate() - diffToMonday);
      const weekKey = monday.toISOString().split('T')[0];
      if (!weeksMap.has(weekKey)) weeksMap.set(weekKey, []);
      weeksMap.get(weekKey)?.push(culto);
    });
    return Array.from(weeksMap.keys()).sort().map(key => weeksMap.get(key) || []);
  }, [sortedCultos]);

  const cultosToShow = viewMode === 'weekly' ? (weeks[selectedWeek] || []) : sortedCultos;

  const weekRangeLabel = useMemo(() => {
    if (viewMode !== 'weekly' || !cultosToShow.length) return "";
    const baseDate = new Date(cultosToShow[0].date + "T12:00:00");
    const day = baseDate.getDay();
    const diffToMonday = day === 0 ? 6 : day - 1;
    const mon = new Date(baseDate);
    mon.setDate(baseDate.getDate() - diffToMonday);
    const sun = new Date(mon);
    sun.setDate(mon.getDate() + 6);
    const mStart = MONTHS[mon.getMonth()].toUpperCase();
    const mEnd = MONTHS[sun.getMonth()].toUpperCase();
    if (mon.getMonth() !== sun.getMonth()) return `${mon.getDate()} de ${mStart} a ${sun.getDate()} de ${mEnd}`;
    return `${mon.getDate()} a ${sun.getDate()} de ${mStart}`;
  }, [cultosToShow, viewMode]);

  const handleExportPDF = () => {
    if (viewMode !== 'print') {
      setViewMode('print');
      setTimeout(() => window.print(), 200);
    } else {
      window.print();
    }
  };

  const handleExportImage = async () => {
    const element = viewMode === 'weekly' ? weeklyExportRef.current : mobileExportRef.current;
    if (!element) return;

    setIsExporting(true);
    await new Promise(resolve => setTimeout(resolve, 500));

    // @ts-ignore
    if (typeof html2canvas !== 'undefined') {
      // @ts-ignore
      html2canvas(element, {
        scale: 3, 
        useCORS: true,
        backgroundColor: "#ffffff",
        logging: false,
        width: 420,
        windowWidth: 420,
        onclone: (clonedDoc: any) => {
          const clonedEl = clonedDoc.getElementById(element.id);
          if (clonedEl) {
            clonedEl.style.opacity = '1';
            clonedEl.style.display = 'flex';
            clonedEl.style.width = '420px';
            clonedEl.style.position = 'relative';
          }
        }
      }).then(async (canvas) => {
        const fileName = `ESCALA_ADFARE_${viewMode === 'weekly' ? 'SEMANAL' : 'MENSAL'}_${MONTHS[data.currentMonth].toUpperCase()}.png`;

        canvas.toBlob(async (blob: Blob | null) => {
          if (!blob) {
            setIsExporting(false);
            return;
          }

          const file = new File([blob], fileName, { type: 'image/png' });

          // @ts-ignore
          if (navigator.canShare && navigator.canShare({ files: [file] })) {
            try {
              await navigator.share({
                files: [file],
                title: 'Escala ADFARE',
                text: WHATSAPP_MESSAGE,
              });
            } catch (err) {
              downloadImage(canvas, fileName);
            }
          } else {
            downloadImage(canvas, fileName);
            const waUrl = `https://wa.me/?text=${encodeURIComponent(WHATSAPP_MESSAGE)}`;
            window.open(waUrl, '_blank');
          }
          setIsExporting(false);
        }, 'image/png');

      }).catch((e) => {
        console.error("Erro na exportação:", e);
        setIsExporting(false);
      });
    } else {
      setIsExporting(false);
    }
  };

  const downloadImage = (canvas: HTMLCanvasElement, fileName: string) => {
    const link = document.createElement('a');
    link.download = fileName;
    link.href = canvas.toDataURL('image/png', 1.0);
    link.click();
  };

  const renderDigitalLayout = (ref: React.RefObject<HTMLDivElement>, id: string, title: string, dateLabel: string, cultos: Culto[], isExport = false) => (
    <div 
      ref={ref} 
      id={id} 
      className={`bg-white w-[420px] flex flex-col p-6 shadow-sm relative overflow-visible box-border ${isExport ? 'fixed left-[-2000px] top-0 z-[-1]' : ''}`}
    >
      <div className="bg-blue-950 rounded-[32px] p-8 pb-10 text-white mb-8 border-b-[6px] border-blue-600 shadow-xl relative z-10 overflow-visible">
        <div className="flex flex-col overflow-visible">
          <div className="flex justify-between items-start mb-6 overflow-visible">
            <div className="flex flex-col">
              <div className="flex items-center gap-2 mb-2">
                <ShieldCheck size={14} className="text-blue-500" />
                <span className="text-[10px] font-black tracking-[0.2em] text-blue-500 uppercase leading-normal">{title}</span>
              </div>
              <h1 className="text-[38px] font-black italic tracking-tight leading-[0.9] text-white uppercase">ADFARE</h1>
            </div>
            <div className="bg-blue-900 w-12 h-12 rounded-xl border border-blue-800 flex items-center justify-center shrink-0">
              <CalendarDays size={20} className="text-blue-300" />
            </div>
          </div>
          <div className="bg-white rounded-[24px] min-h-[64px] py-4 px-6 border-[3px] border-blue-800 flex items-center justify-center shadow-inner overflow-visible">
            <span className="text-[19px] font-black uppercase tracking-tight leading-tight text-blue-950 block text-center">
              {dateLabel}
            </span>
          </div>
        </div>
      </div>

      <div className="space-y-4 mb-8 overflow-visible">
        {cultos.length === 0 ? (
          <div className="py-20 text-center text-slate-300 font-black uppercase text-xs italic tracking-widest leading-none">Nenhuma escala para exibir em {MONTHS[data.currentMonth].toUpperCase()}</div>
        ) : (
          cultos.map((culto) => (
            <div key={culto.id} className={`rounded-[32px] p-5 shadow-sm border-[2px] flex flex-col gap-5 overflow-visible ${culto.isSantaCeia ? 'bg-purple-900 border-purple-800 text-white' : 'bg-white border-slate-100'}`}>
              <div className="flex items-start gap-5 overflow-visible">
                <div className={`w-16 h-16 rounded-[24px] flex flex-col items-center justify-center shrink-0 shadow-md ${culto.isSantaCeia ? 'bg-white text-purple-900' : 'bg-blue-900 text-white'}`}>
                  <span className="text-[9px] font-black opacity-60 uppercase leading-none mb-1 text-center w-full">{DAYS_SHORT[culto.dayOfWeek]}</span>
                  <span className="text-[28px] font-black leading-none text-center w-full">{culto.date.split('-')[2]}</span>
                </div>
                <div className="flex-grow min-w-0 overflow-visible">
                  <div className="flex justify-between items-center mb-3 overflow-visible">
                    <h4 className={`text-[13px] font-black uppercase leading-tight pr-3 truncate ${culto.isSantaCeia ? 'text-white' : 'text-slate-900'}`}>{culto.isSantaCeia ? '★ SANTA CEIA' : culto.name}</h4>
                    <div className={`shrink-0 text-[10px] font-black px-3 py-1.5 rounded-full flex items-center justify-center leading-none ${culto.isSantaCeia ? 'bg-purple-800 text-white' : 'bg-blue-50 text-blue-900'}`}>
                      {culto.time}H
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-3 overflow-visible">
                    <div className={`flex flex-col p-3 rounded-[20px] min-w-0 overflow-visible ${culto.isSantaCeia ? 'bg-white/10' : 'bg-slate-50'}`}>
                      <div className="flex items-center gap-1.5 mb-2 overflow-visible"><Key size={12} className={culto.isSantaCeia ? 'text-purple-300' : 'text-blue-600'} /><span className={`text-[8px] font-black uppercase leading-none ${culto.isSantaCeia ? 'text-purple-300' : 'text-slate-400'}`}>Abertura</span></div>
                      <span className={`text-[10px] font-black uppercase leading-tight truncate pb-1 ${culto.isSantaCeia ? 'text-white' : 'text-slate-800'}`}>{getWorkerDisplayName(culto.workersAbertura[0])}</span>
                    </div>
                    <div className={`flex flex-col p-3 rounded-[20px] min-w-0 overflow-visible ${culto.isSantaCeia ? 'bg-white/10' : 'bg-slate-50'}`}>
                      <div className="flex items-center gap-1.5 mb-2 overflow-visible"><Users size={12} className={culto.isSantaCeia ? 'text-purple-300' : 'text-emerald-600'} /><span className={`text-[8px] font-black uppercase leading-none ${culto.isSantaCeia ? 'text-purple-300' : 'text-slate-400'}`}>Apoio</span></div>
                      <span className={`text-[10px] font-black uppercase leading-tight truncate pb-1 ${culto.isSantaCeia ? 'text-white' : 'text-slate-800'}`}>{getWorkerDisplayName(culto.workersApoio[0])}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )
        ))}
      </div>

      <div className="bg-white rounded-[32px] p-8 border border-slate-100 shadow-sm relative mb-10 overflow-visible">
        <div className="absolute top-0 left-0 w-2 h-full bg-blue-600"></div>
        <div className="flex items-start gap-4 overflow-visible">
          <Quote size={28} className="text-blue-100 shrink-0" />
          <div className="flex-grow overflow-visible">
            <p className="text-[14px] font-bold text-slate-700 italic leading-[1.6] mb-5">
              "Portanto, meus amados irmãos, sede firmes e constantes, sempre abundantes na obra do Senhor, sabendo que o vosso trabalho não é vão no Senhor."
            </p>
            <div className="flex items-center gap-3 overflow-visible">
              <div className="h-[2px] w-6 bg-blue-600 rounded-full"></div>
              <span className="text-[10px] font-black text-blue-900 uppercase tracking-widest leading-normal">1 Coríntios 15:58</span>
            </div>
          </div>
        </div>
      </div>

      <div className="mt-auto pt-6 pb-4 flex flex-col items-center gap-2 text-center opacity-30 overflow-visible">
        <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.4em] leading-none">Família Restaurada</span>
        <span className="text-[7px] font-bold text-slate-600 uppercase tracking-[0.1em] leading-none">Gerenciamento Digital ADFARE</span>
      </div>
    </div>
  );

  return (
    <div className="space-y-4 pb-20">
      {/* Filtros e Controles */}
      <div className="bg-white p-5 rounded-[32px] shadow-sm border border-slate-100 no-print space-y-4">
        <div className="flex flex-col gap-4">
          <div className="flex gap-2">
            <div className="flex-grow relative">
               <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-blue-900/30" size={18} />
               <select 
                value={data.currentMonth} 
                onChange={handleMonthChange} 
                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-100 rounded-2xl font-black text-blue-900 uppercase text-xs outline-none focus:ring-2 focus:ring-blue-100 transition-all appearance-none"
              >
                {MONTHS.map((m, idx) => <option key={m} value={idx}>{m}</option>)}
              </select>
            </div>
            <select 
              value={data.currentYear} 
              onChange={handleYearChange} 
              className="min-w-[100px] px-4 py-3 bg-slate-50 border border-slate-100 rounded-2xl font-black text-blue-900 text-xs outline-none focus:ring-2 focus:ring-blue-100 transition-all appearance-none text-center"
            >
              {years.map(y => <option key={y} value={y}>{y}</option>)}
            </select>
          </div>

          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
            <input type="text" placeholder="Buscar por nome do obreiro..." value={filterName} onChange={e => setFilterName(e.target.value)} className="w-full pl-9 pr-8 py-3 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm text-slate-900 outline-none placeholder:text-slate-300" />
            {filterName && <button onClick={() => setFilterName('')} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-rose-500 transition-colors"><X size={14} /></button>}
          </div>

          <div className="flex bg-slate-100 p-1 rounded-2xl">
            <button onClick={() => setViewMode('weekly')} className={`flex-1 py-3 rounded-xl text-[9px] font-black uppercase flex items-center justify-center gap-1.5 transition-all ${viewMode === 'weekly' ? 'bg-white text-blue-900 shadow-sm' : 'text-slate-400'}`}><Zap size={14} /> Semana</button>
            <button onClick={() => setViewMode('mobile')} className={`flex-1 py-3 rounded-xl text-[9px] font-black uppercase flex items-center justify-center gap-1.5 transition-all ${viewMode === 'mobile' ? 'bg-white text-blue-900 shadow-sm' : 'text-slate-400'}`}><Smartphone size={14} /> Mês</button>
            <button onClick={() => setViewMode('print')} className={`flex-1 py-3 rounded-xl text-[9px] font-black uppercase flex items-center justify-center gap-1.5 transition-all ${viewMode === 'print' ? 'bg-white text-blue-900 shadow-sm' : 'text-slate-400'}`}><Printer size={14} /> Mural</button>
          </div>
        </div>

        {viewMode === 'weekly' && weeks.length > 0 && (
          <div className="flex items-center justify-between bg-blue-50 p-2 rounded-2xl border border-blue-100">
            <button disabled={selectedWeek === 0} onClick={() => setSelectedWeek(w => Math.max(0, w - 1))} className="p-2 text-blue-900 disabled:opacity-20 active:scale-90 transition-transform"><ChevronLeft size={24} /></button>
            <div className="text-center px-2 min-w-0">
              <span className="text-[10px] font-black text-blue-900 uppercase tracking-widest leading-none">Semana {selectedWeek + 1}</span>
              <p className="text-[8px] font-bold text-blue-400 uppercase tracking-tight mt-0.5 truncate leading-none">{weekRangeLabel.toLowerCase()}</p>
            </div>
            <button disabled={selectedWeek === weeks.length - 1} onClick={() => setSelectedWeek(w => Math.min(weeks.length - 1, w + 1))} className="p-2 text-blue-900 disabled:opacity-20 active:scale-90 transition-transform"><ChevronRight size={24} /></button>
          </div>
        )}

        <div className="grid grid-cols-2 gap-3">
          <button onClick={() => handleExportPDF()} disabled={isExporting || cultosToShow.length === 0} className="py-4 bg-blue-900 text-white rounded-2xl font-black flex items-center justify-center gap-2 text-[10px] uppercase tracking-widest shadow-xl active:scale-95 transition-all disabled:opacity-50">
            <FileDown size={14} /> Salvar PDF
          </button>
          <button onClick={handleExportImage} disabled={isExporting || cultosToShow.length === 0 || viewMode === 'print'} className="py-4 bg-emerald-600 text-white rounded-2xl font-black flex items-center justify-center gap-2 text-[10px] uppercase tracking-widest shadow-xl active:scale-95 transition-all disabled:opacity-50">
            {isExporting ? <div className="animate-spin h-3 w-3 border-2 border-white border-t-transparent rounded-full" /> : <Share2 size={14} />} 
            {isExporting ? 'Processando...' : 'ZAP / Imagem'}
          </button>
        </div>
      </div>

      {/* RENDERIZADORES DE EXPORTAÇÃO (OCULTOS) */}
      <div className="pointer-events-none opacity-0 h-0 overflow-hidden">
        {renderDigitalLayout(weeklyExportRef, 'weekly-export-container', 'ESCALA SEMANAL', weekRangeLabel || '---', weeks[selectedWeek] || [], true)}
        {renderDigitalLayout(mobileExportRef, 'mobile-export-container', 'ESCALA MENSAL', `${MONTHS[data.currentMonth].toUpperCase()} ${data.currentYear}`, sortedCultos, true)}
      </div>

      {/* Visualização da Escala Digital */}
      <div className="flex flex-col items-center gap-6 pb-20 overflow-visible no-print">
        <div className="scale-[0.85] sm:scale-100 origin-top overflow-visible">
          {viewMode === 'weekly' && renderDigitalLayout(weeklyPreviewRef, 'weekly-preview', 'ESCALA SEMANAL', weekRangeLabel || '---', cultosToShow)}
          {viewMode === 'mobile' && renderDigitalLayout(mobilePreviewRef, 'mobile-preview', 'ESCALA MENSAL', `${MONTHS[data.currentMonth].toUpperCase()} ${data.currentYear}`, sortedCultos)}
        </div>
      </div>

      {/* Layout de Impressão */}
      {viewMode === 'print' && (
        <div className="w-full overflow-hidden flex justify-center pb-10 sm:block">
          <div className="relative" style={{ width: '794px', height: '1123px' }}>
             <div className="absolute left-1/2 -translate-x-1/2 origin-top scale-[0.45] sm:scale-100 sm:relative sm:left-0 sm:translate-x-0">
              <div className="bg-white shadow-2xl overflow-hidden flex flex-col border border-slate-200 p-[40px] pdf-page-canvas" ref={reportRef}>
